import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulated user input from a form or user input field
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Encode the user input to prevent XSS attacks
        String encodedInput = ESAPI.encoder().encodeForHTML(userInput);

        // Displaying the sanitized user input on a webpage
        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html><body>");
            out.println("<h1>Welcome, " + encodedInput + "</h1>");
            out.println("</body></html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
